import { UmbTextStyles } from "@umbraco-cms/backoffice/style";
import {
  css,
  html,
  customElement,
  state,
  LitElement,
  when,
} from "@umbraco-cms/backoffice/external/lit";
import { UmbWorkspaceViewElement } from "@umbraco-cms/backoffice/workspace";
import { UmbElementMixin } from "@umbraco-cms/backoffice/element-api";
import type { FormDesign } from "@umbraco-forms/generated";
import { FORMS_FORM_WORKSPACE_CONTEXT } from "../../form-workspace.context-token.js";
import { FORMS_CONTEXT } from "@umbraco-forms/context";

const elementName = "workspace-view-form-settings";

@customElement(elementName)
export class UmbWorkspaceViewFormSettingsElement
  extends UmbElementMixin(LitElement)
  implements UmbWorkspaceViewElement
{
  @state()
  _form?: FormDesign;

  #workspaceContext?: typeof FORMS_FORM_WORKSPACE_CONTEXT.TYPE;

  #enableMultiPageFormSettings: boolean = false;

  constructor() {
    super();

    this.consumeContext(FORMS_FORM_WORKSPACE_CONTEXT, (instance) => {
      this.#workspaceContext = instance;
      this.#observeForm();
    });

    this.consumeContext(FORMS_CONTEXT, (instance) => {
      if (!instance) return;
      this.observe(instance.config, (config) => {
        if (config) {
          this.#enableMultiPageFormSettings = config?.enableMultiPageFormSettings;
        }
      });
    });
  }

  #observeForm() {
    if (!this.#workspaceContext) return;

    this.observe(this.#workspaceContext.data, (form) => {
      if (!form) return;
      this._form = form;
    });
  }

  render() {
    return html`<uui-box>
      <forms-settings-store-records></forms-settings-store-records>
      <forms-settings-captions></forms-settings-captions>
      <forms-settings-styling></forms-settings-styling>
      <forms-settings-validation></forms-settings-validation>
      <forms-settings-autocomplete></forms-settings-autocomplete>
      ${when(
        this.#enableMultiPageFormSettings,
        () =>
          html`<forms-settings-multi-page></forms-settings-multi-page>`
      )}
      <forms-settings-moderation></forms-settings-moderation>
      <forms-settings-fields-display
        .formFields=${this.#workspaceContext?.getAllFields() ?? []}
      ></forms-settings-fields-display>
      ${when(
        this._form?.storeRecordsLocally,
        () =>
          html`<forms-settings-data-retention></forms-settings-data-retention>`
      )}
    </uui-box>`;
  }

  static styles = [
    UmbTextStyles,
    css`
      :host {
        display: block;
        padding: var(--uui-size-layout-1);
      }
    `,
  ];
}

export default UmbWorkspaceViewFormSettingsElement;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: UmbWorkspaceViewFormSettingsElement;
  }
}
